```python
def even_odd_palindrome(n):
    def is_palindrome(num):
        s = str(num)
        return s == s[::-1]

    even_count = 0
    odd_count = 0

    for i in range(1, n + 1):
        if is_palindrome(i):
            if i % 2 == 0:
                even_count += 1
            else:
                odd_count += 1

    return (even_count, odd_count)
```

