```python
def unique_digits(x):
    def has_no_even_digits(num):
        # Convert number to string to check each digit
        for digit_char in str(num):
            digit = int(digit_char)
            # Check if digit is even (0, 2, 4, 6, 8)
            if digit % 2 == 0:
                return False
        return True

    # Filter numbers that have no even digits
    result = [num for num in x if has_no_even_digits(num)]

    # Return sorted list in ascending order
    return sorted(result)
```

