```python
def change_base(x: int, base: int) -> str:
    if x == 0:
        return '0'

    result = ''
    while x > 0:
        result = str(x % base) + result
        x = x // base

    return result
```

```python
def prime_length(string):
    def is_prime(n):
        if n < 2:
            return False
        if n == 2:
            return True
        if n % 2 == 0:
            return False
        for i in range(3, int(n**0.5) + 1, 2):
            if n % i == 0:
                return False
        return True

    return is_prime(len(string))
```

