```python
def string_xor(a: str, b: str) -> str:
    result = []
    for i in range(len(a)):
        # XOR: same bits give 0, different bits give 1
        if a[i] == b[i]:
            result.append('0')
        else:
            result.append('1')
    return ''.join(result)
```

