```python
def add(lst):
    total = 0
    for i in range(len(lst)):
        if i % 2 == 1:  # odd index (1, 3, 5, ...)
            if lst[i] % 2 == 0:  # even element
                total += lst[i]
    return total
```

```python
def add(lst):
    total = 0
    for i in range(len(lst)):
        if i % 2 == 1:  # odd index (1, 3, 5, ...)
            if lst[i] % 2 == 0:  # even element
                total += lst[i]
    return total
```

```python
def any_int(x, y, z):
    # Check if all numbers are integers
    # We need to handle both int type and float values that represent integers (like 5.0)
    def is_integer(num):
        if isinstance(num, int):
            return True
        elif isinstance(num, float):
            return num.is_integer()
        else:
            return False

    if not (is_integer(x) and is_integer(y) and is_integer(z)):
        return False

    # Check if any number equals the sum of the other two
    return x == y + z or y == x + z or z == x + y
```

```python
def any_int(x, y, z):
    # Check if all three numbers are integers
    # We need to check if they are actual integers (not floats that happen to be whole numbers)
    # Using isinstance to check for int type, and also handle float values that represent integers
    def is_integer(num):
        return isinstance(num, int) or (isinstance(num, float) and num.is_integer())

    if not (is_integer(x) and is_integer(y) and is_integer(z)):
        return False

    # Convert to int if they are floats representing integers
    x_int = int(x) if isinstance(x, float) else x
    y_int = int(y) if isinstance(y, float) else y
    z_int = int(z) if isinstance(z, float) else z

    # Check if any number equals the sum of the other two
    return (x_int == y_int + z_int) or (y_int == x_int + z_int) or (z_int == x_int + y_int)
```

