    # Handle case where x > y (invalid range)
    if x > y:
        return -1

    # Start from the largest number in range (y) and work backwards
    # Find the largest even number in [x, y]
    if y % 2 == 0:
        # y is even, so it's the largest even number in range if it's >= x
        if y >= x:
            return y
    else:
        # y is odd, so check y-1
        if y - 1 >= x:
            return y - 1

    # If no even number found in range
    return -1
